evaluators.evaluation_logic:
const checkpoints = [];

const filterParams = JSON.parse(localStorage.getItem('task1_filterParams') || 'null');
const demos = JSON.parse(localStorage.getItem('voiceover_demos') || '[]');
const favorites = JSON.parse(localStorage.getItem('favorite_voiceover_demos') || '[]');

// Determine qualifying demos: English commercial, duration <= 30s
const qualifying = demos.filter(d => 
  d && d.category === 'commercial' &&
  d.language === 'English' &&
  typeof d.duration_seconds === 'number' &&
  d.duration_seconds <= 30
);

// Sort qualifying demos by most recent (created_at desc)
qualifying.sort((a, b) => ((b.created_at || '')).localeCompare(a.created_at || ''));
const top3 = qualifying.slice(0, 3);
const top3Ids = top3.map(d => d.id);

// Count how many of these top 3 are in favorites
const favoritedCount = top3Ids.filter(id => favorites.some(f => f.demo_id === id)).length;

// CP1 (0.30): Used correct search filters (commercial, English, <=30s, most recent)
const usedCorrectFilters = !!filterParams &&
  filterParams.category === 'commercial' &&
  Array.isArray(filterParams.languages) &&
  filterParams.languages.includes('English') &&
  typeof filterParams.max_duration_seconds === 'number' &&
  filterParams.max_duration_seconds <= 30 &&
  (filterParams.sort_by === 'most_recent' || filterParams.sort_by === 'newest_first');
checkpoints.push({ passed: usedCorrectFilters, weight: 0.30 });

// CP2-CP4: Favorited the newest qualifying demos (only counting correct targets)
[1, 2, 3].forEach((n, idx) => {
  checkpoints.push({
    passed: favoritedCount >= n && top3.length >= n,
    weight: idx === 0 ? 0.20 : 0.25
  });
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const filterParams = JSON.parse(localStorage.getItem('task2_filterParams') || 'null');
let comparedDemoIds;
try {
  comparedDemoIds = JSON.parse(localStorage.getItem('task2_comparedDemoIds') || '[]');
} catch (e) {
  comparedDemoIds = [];
}
const demos = JSON.parse(localStorage.getItem('voiceover_demos') || '[]');
const shortlistItems = JSON.parse(localStorage.getItem('project_shortlist_items') || '[]');

// Compute the ordered list of English character video_game_animation demos, newest first
const filtered = demos.filter(d => 
  d && d.category === 'character' &&
  d.language === 'English' &&
  d.style === 'video_game_animation'
);
filtered.sort((a, b) => ((b.created_at || '')).localeCompare(a.created_at || ''));
const firstTwo = filtered.slice(0, 2);
const firstTwoIds = firstTwo.map(d => d.id);

let longerDemo = null;
if (firstTwo.length === 1) {
  longerDemo = firstTwo[0];
} else if (firstTwo.length === 2) {
  const d0 = firstTwo[0];
  const d1 = firstTwo[1];
  const dur0 = typeof d0.duration_seconds === 'number' ? d0.duration_seconds : 0;
  const dur1 = typeof d1.duration_seconds === 'number' ? d1.duration_seconds : 0;
  longerDemo = dur0 >= dur1 ? d0 : d1;
}

// CP1 (0.30): Used correct filters for the comparison set
const usedCorrectFilters = !!filterParams &&
  filterParams.category === 'character' &&
  Array.isArray(filterParams.languages) &&
  filterParams.languages.includes('English') &&
  filterParams.style === 'video_game_animation' &&
  (filterParams.sort_by === 'most_recent' || filterParams.sort_by === 'newest_first');
checkpoints.push({ passed: usedCorrectFilters, weight: 0.30 });

// CP2 (0.30): Viewed both of the first two newest qualifying demos in detail
const viewedBoth = firstTwoIds.length === 2 &&
  Array.isArray(comparedDemoIds) &&
  firstTwoIds.every(id => comparedDemoIds.includes(id));
checkpoints.push({ passed: viewedBoth, weight: 0.30 });

// CP3 (0.40): Added the longer of the first two demos to the project shortlist
const addedCorrect = !!longerDemo && shortlistItems.some(it => it.demo_id === longerDemo.id);
checkpoints.push({ passed: addedCorrect, weight: 0.40 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const filterParams = JSON.parse(localStorage.getItem('task3_filterParams') || 'null');
const showreels = JSON.parse(localStorage.getItem('showreels') || '[]');
const castingItems = JSON.parse(localStorage.getItem('casting_list_items') || '[]');

// Determine qualifying showreels: drama, year >= 2019, duration >= 60s
const qualifying = showreels.filter(s => 
  s && s.genre === 'drama' &&
  typeof s.year_filmed === 'number' && s.year_filmed >= 2019 &&
  typeof s.duration_seconds === 'number' && s.duration_seconds >= 60
);

// Sort as 'most_recent': year_filmed desc, then created_at desc
qualifying.sort((a, b) => {
  const ya = typeof a.year_filmed === 'number' ? a.year_filmed : 0;
  const yb = typeof b.year_filmed === 'number' ? b.year_filmed : 0;
  if (yb !== ya) return yb - ya;
  return (b.created_at || '').localeCompare(a.created_at || '');
});

const top2 = qualifying.slice(0, 2);
const top2Ids = top2.map(s => s.id);

// Count how many of these top 2 are in the casting list
const addedCount = top2Ids.filter(id => castingItems.some(it => it.showreel_id === id)).length;

// CP1 (0.30): Used correct search filters
const usedCorrectFilters = !!filterParams &&
  filterParams.genre === 'drama' &&
  typeof filterParams.min_year === 'number' && filterParams.min_year >= 2019 &&
  typeof filterParams.min_duration_seconds === 'number' && filterParams.min_duration_seconds >= 60 &&
  (filterParams.sort_by === 'most_recent' || filterParams.sort_by === 'most_recent_first');
checkpoints.push({ passed: usedCorrectFilters, weight: 0.30 });

// CP2 (0.30): Added at least the single newest qualifying showreel
checkpoints.push({
  passed: addedCount >= 1 && top2.length >= 1,
  weight: 0.30
});

// CP3 (0.40): Added both of the two newest qualifying showreels
checkpoints.push({
  passed: addedCount >= 2 && top2.length >= 2,
  weight: 0.40
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const inquiries = JSON.parse(localStorage.getItem('quote_inquiries') || '[]');
const quotes = JSON.parse(localStorage.getItem('rate_quotes') || '[]');

// Find the most recent inquiry matching project type, duration ~60s, online worldwide, and budget <= 600
let candidate = null;
for (const iq of inquiries) {
  if (!iq) continue;
  if (iq.project_type !== 'online_ad_web_commercial') continue;
  if (iq.territory !== 'online_worldwide') continue;
  if (typeof iq.script_length_seconds !== 'number') continue;
  if (iq.script_length_seconds < 50 || iq.script_length_seconds > 70) continue; // approximately 60s
  if (typeof iq.budget_limit !== 'number' || iq.budget_limit > 600) continue;

  if (!candidate || (iq.created_at || '') > (candidate.created_at || '')) {
    candidate = iq;
  }
}

// Find a matching rate quote for the candidate with estimated_fee <= 600
let matchingQuote = null;
if (candidate) {
  matchingQuote = quotes.find(q => 
    q &&
    q.project_type === candidate.project_type &&
    q.script_length_seconds === candidate.script_length_seconds &&
    q.usage_duration === candidate.usage_duration &&
    q.territory === candidate.territory &&
    typeof q.estimated_fee === 'number' &&
    q.estimated_fee <= 600
  ) || null;
}

// CP1 (0.50): Submitted an appropriate quote inquiry configuration within budget
const cp1Passed = !!candidate;
checkpoints.push({ passed: cp1Passed, weight: 0.50 });

// CP2 (0.50): There is a calculator quote for that configuration with estimate <= $600
const cp2Passed = !!matchingQuote;
checkpoints.push({ passed: cp2Passed, weight: 0.50 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const bookings = JSON.parse(localStorage.getItem('booking_requests') || '[]');

// Choose a single candidate booking that matches session type and length
let candidate = null;
for (const br of bookings) {
  if (!br) continue;
  if (br.session_type !== 'directed_remote_recording_session') continue;
  if (typeof br.session_length_hours !== 'number' || br.session_length_hours !== 2) continue;
  candidate = br;
  break;
}

// CP1 (0.40): Correct session type and 2-hour length
const cp1Passed = !!candidate;
checkpoints.push({ passed: cp1Passed, weight: 0.40 });

let cp2Passed = false;
let cp3Passed = false;

if (candidate) {
  // Check date, time, and timezone
  const tzOk = typeof candidate.timezone === 'string' && candidate.timezone.indexOf('America/New_York') === 0;

  let dateOk = false;
  if (candidate.session_start) {
    const dt = new Date(candidate.session_start);
    if (!isNaN(dt.getTime())) {
      const year = dt.getUTCFullYear();
      const month = dt.getUTCMonth(); // 0-based, 3 = April
      const day = dt.getUTCDate();
      const hour = dt.getUTCHours();
      // Mid-April 2026 (10th–20th) at 10:00 (UTC, as stored by helper)
      dateOk = (year === 2026 && month === 3 && day >= 10 && day <= 20 && hour === 10);
    }
  }
  cp2Passed = tzOk && dateOk;

  // Check two distinct preferred connection methods
  const methods = Array.isArray(candidate.preferred_connection_methods) ? candidate.preferred_connection_methods : [];
  const uniqueMethods = Array.from(new Set(methods.filter(m => typeof m === 'string' && m.trim().length > 0)));
  cp3Passed = uniqueMethods.length >= 2;
}

// CP2 (0.30): Scheduled in mid-April 2026 at 10:00 AM in US Eastern timezone
checkpoints.push({ passed: cp2Passed, weight: 0.30 });

// CP3 (0.30): Selected at least two distinct preferred connection methods
checkpoints.push({ passed: cp3Passed, weight: 0.30 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const filterParams = JSON.parse(localStorage.getItem('task6_filterParams') || 'null');
const favoritesSortBy = localStorage.getItem('task6_favoriteClientsSortBy');
const testimonials = JSON.parse(localStorage.getItem('testimonials') || '[]');
const clients = JSON.parse(localStorage.getItem('clients') || '[]');
const favoriteClients = JSON.parse(localStorage.getItem('favorite_clients') || '[]');

// Build enriched testimonials with client data and filter to ad/marketing agencies, year >= 2022
const enriched = testimonials.map(t => {
  const client = clients.find(c => c.id === t.client_id) || null;
  return { ...t, client };
}).filter(t => 
  t.client &&
  t.client.client_type === 'advertising_marketing_agency' &&
  typeof t.year === 'number' && t.year >= 2022
);

// Sort by most recent first (date_desc)
enriched.sort((a, b) => (b.date || '').localeCompare(a.date || ''));

// Collect up to three most recent UNIQUE client_ids from these testimonials
const targetClientIds = [];
const seen = new Set();
for (const t of enriched) {
  if (!seen.has(t.client_id)) {
    seen.add(t.client_id);
    targetClientIds.push(t.client_id);
  }
  if (targetClientIds.length >= 3) break;
}

// Count how many of the target clients are in favorites
const qualifyingFavCount = targetClientIds.filter(id => favoriteClients.some(f => f.client_id === id)).length;

// CP1 (0.25): Used correct testimonial filters
const usedCorrectFilters = !!filterParams &&
  filterParams.client_type === 'advertising_marketing_agency' &&
  typeof filterParams.min_year === 'number' && filterParams.min_year >= 2022 &&
  (filterParams.sort_by === 'date_desc' || filterParams.sort_by === 'newest_first');
checkpoints.push({ passed: usedCorrectFilters, weight: 0.25 });

// CP2 (0.15): Viewed favorite clients sorted alphabetically by company name
const usedCorrectFavSort = favoritesSortBy === 'company_name_asc' || favoritesSortBy === 'company_name_a_z';
checkpoints.push({ passed: usedCorrectFavSort, weight: 0.15 });

// CP3-CP5: Favorited clients corresponding to the three most recent unique ad-agency testimonials
[1, 2, 3].forEach((n) => {
  checkpoints.push({
    passed: qualifyingFavCount >= n && targetClientIds.length >= n,
    weight: 0.20
  });
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const serviceOptions = JSON.parse(localStorage.getItem('service_options') || '[]');
const plans = JSON.parse(localStorage.getItem('project_plans') || '[]');
const planItemsAll = JSON.parse(localStorage.getItem('project_plan_service_items') || '[]');

// Find a plan that includes both a commercial VO service and an on-camera self-tape acting service, with total duration <= 3 hours
let candidate = null;
for (const plan of plans) {
  if (!plan) continue;
  const items = planItemsAll.filter(it => it.project_plan_id === plan.id);
  if (items.length === 0) continue;

  let hasCommercialVO = false;
  let hasOnCameraSelfTape = false;

  for (const it of items) {
    const so = serviceOptions.find(s => s.id === it.service_option_id);
    if (!so || !so.is_active) continue;
    const name = (so.name || '').toLowerCase();
    if (so.service_category === 'voiceover' && name.includes('commercial voiceover')) {
      hasCommercialVO = true;
    }
    if (so.service_category === 'acting' && name.includes('on-camera self-tape')) {
      hasOnCameraSelfTape = true;
    }
  }

  if (hasCommercialVO && hasOnCameraSelfTape && typeof plan.total_duration_hours === 'number' && plan.total_duration_hours <= 3) {
    candidate = { plan, items };
    break;
  }
}

// CP1 (0.40): Plan combines commercial VO + on-camera self-tape within 3 hours
const cp1Passed = !!candidate;
checkpoints.push({ passed: cp1Passed, weight: 0.40 });

let cp2Passed = false;
let cp3Passed = false;

if (candidate) {
  // CP2: Budget note indicates a numeric maximum budget under $1,000
  const budgetNote = candidate.plan.budget_note || '';
  const match = budgetNote.match(/(?:\$|usd)\s*([0-9]+)/i);
  if (match) {
    const amount = parseInt(match[1], 10);
    if (!isNaN(amount) && amount < 1000) {
      cp2Passed = true;
    }
  }

  // CP3: Notes mention prioritizing the commercial voiceover if schedule is tight
  const notes = (candidate.plan.notes || '').toLowerCase();
  if (notes.includes('priorit') && notes.includes('voiceover')) {
    cp3Passed = true;
  }
}

// CP2 (0.30): Budget under $1,000 captured in budget note
checkpoints.push({ passed: cp2Passed, weight: 0.30 });

// CP3 (0.30): Notes state that commercial voiceover should be prioritized
checkpoints.push({ passed: cp3Passed, weight: 0.30 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const subs = JSON.parse(localStorage.getItem('newsletter_subscriptions') || '[]');

// Find a subscription with an example.com email that appears casting-related
let candidate = null;
for (const s of subs) {
  if (!s || typeof s.email !== 'string') continue;
  const parts = s.email.split('@');
  if (parts.length !== 2) continue;
  const local = parts[0].toLowerCase();
  const domain = parts[1].toLowerCase();
  if (domain === 'example.com' && local.includes('casting')) {
    candidate = s;
    break;
  }
}

// CP1 (0.50): Subscribed with a casting-related email at example.com
const cp1Passed = !!candidate;
checkpoints.push({ passed: cp1Passed, weight: 0.50 });

let cp2Passed = false;
if (candidate) {
  const interests = Array.isArray(candidate.interests) ? candidate.interests : [];
  const hasAllInterests = ['commercial_voiceover', 'animation', 'drama_acting'].every(id => interests.includes(id));
  const correctFreq = candidate.summary_frequency === 'monthly_summary';
  const noWeekly = candidate.wants_weekly_tips === false; // explicitly disabled
  const castingUpdates = candidate.wants_casting_availability_updates === true;
  cp2Passed = hasAllInterests && correctFreq && noWeekly && castingUpdates;
}

// CP2 (0.50): Correct interests, monthly summary only, no weekly emails, casting updates enabled
checkpoints.push({ passed: cp2Passed, weight: 0.50 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
